#include <Arduino.h>
#include <lvgl.h>
#include "display_st7701.hpp"
#include "touch_cst820.hpp"
#include "lvgl_port.hpp"
#include "gauge_speed.hpp"
#include "data/twai_driver.hpp"

void setup(void) {
    Serial.begin(115200);
    Serial.println("OGauge: Needle gauge demo");
    Serial.println("I2C init...");
    I2C_init();
    Serial.println("TCA9554 init...");
    TCA9554_init(0x00);
    Serial.println("Display init...");
    Display_init();
    Serial.println("Touch init...");
    Touch_init();
    Serial.println("LVGL init...");
    lv_init();
    LvglPort_init();
    Serial.println("Gauge init...");
    GaugeSpeed_create();
    Serial.println("TWAI init...");
    TwaiDriver_init();
    Serial.println("Ready!");
}

void loop(void) {
    TwaiDriver_poll();
    LvglPort_loop();
    delay(5);
}
